data.prepare:
// DataLens Advanced chart (Prepare tab) — индикатор лидов с MoM сравнением.
// Ожидается, что во вкладке Sources есть источник `svodny_source`
// с полями как минимум: creation_date, geo, utmsource, leads_sum (мерой SUM).
// Для фильтров utmsource/lang/pipeline_id добавь эти поля в Sources (dimension).

const params = Editor.getParams() || {};
const loaded = Editor.getLoadedData() || {};
const src = loaded.svodny_source || {};

function extractRows(srcObj) {
  if (!srcObj) return [];
  const std = srcObj.result?.data?.Data;
  if (Array.isArray(std)) return std;

  const blocks = srcObj.result_data || {};
  const keys = Object.keys(blocks).sort((a, b) => Number(a) - Number(b));
  const out = [];
  for (const k of keys) {
    const b = blocks[k];
    if (b?.rows) {
      for (const r of b.rows) {
        if (Array.isArray(r?.data)) out.push(r.data);
      }
    }
  }
  return out;
}

function cellValue(x) {
  if (x == null) return null;
  if (typeof x === 'object') return x.raw ?? x.value ?? x.formatted ?? null;
  return x;
}

function safeNum(x) {
  const n = Number(cellValue(x));
  return isFinite(n) ? n : 0;
}

function parseDateRange(selRaw) {
  const arr = Array.isArray(selRaw) ? selRaw : (selRaw ? [selRaw] : []);
  let fromStr = null, toStr = null;

  if (arr.length >= 2) {
    fromStr = String(arr[0]).slice(0, 10);
    toStr = String(arr[1]).slice(0, 10);
  } else if (arr.length === 1) {
    const s = String(arr[0]);
    const dates = s.match(/\d{4}-\d{2}-\d{2}/g);
    if (dates?.length >= 2) {
      fromStr = dates[0];
      toStr = dates[1];
    } else if (dates?.length === 1) {
      fromStr = toStr = dates[0];
    } else if (!s.startsWith('__interval')) {
      fromStr = toStr = s.slice(0, 10);
    }
  }

  if (!fromStr || !toStr) {
    const cutoff = new Date();
    cutoff.setMonth(cutoff.getMonth() - 3);
    cutoff.setHours(0, 0, 0, 0);
    fromStr = cutoff.toISOString().slice(0, 10);
    toStr = new Date().toISOString().slice(0, 10);
  }

  return { fromStr, toStr, sel: arr };
}

function parseStringFilter(selRaw) {
  const arr = Array.isArray(selRaw) ? selRaw : (selRaw ? [selRaw] : []);
  const values = [];

  for (const v of arr) {
    const s = String(v ?? '').trim();
    if (!s) continue;

    const op = Editor.resolveOperation(s);
    if (op && op.value != null) {
      if (Array.isArray(op.value)) for (const x of op.value) values.push(String(x));
      else values.push(String(op.value));
      continue;
    }

    if (!s.startsWith('__')) values.push(s);
  }

  return Array.from(new Set(values));
}

function shiftMonth(isoStr, deltaMonths) {
  const d = new Date(isoStr + 'T00:00:00Z');
  d.setUTCMonth(d.getUTCMonth() + deltaMonths);
  return d.toISOString().slice(0, 10);
}

function fmtRu(isoStr) {
  const s = String(isoStr || '').slice(0, 10);
  const p = s.split('-');
  return p.length === 3 ? `${p[2]}.${p[1]}.${p[0]}` : s;
}

function fmtRuShort(isoStr) {
  const s = String(isoStr || '').slice(0, 10);
  const p = s.split('-');
  return p.length === 3 ? `${p[2]}.${p[1]}` : s;
}

function buildIndexMap(srcObj) {
  const map = {};
  const fields = srcObj && srcObj.fields;

  if (Array.isArray(fields)) {
    for (let i = 0; i < fields.length; i++) {
      const f = fields[i] || {};
      const title =
        f.title ||
        (f.ref && f.ref.title) ||
        f.name;
      if (title) map[title] = i;
    }
  }

  // fallback на типовой порядок полей в Sources:
  // [creation_date, geo, utmsource, lang, pipeline_id, leads_sum]
  if (map.creation_date == null) map.creation_date = 0;
  if (map.geo == null) map.geo = 1;
  if (map.utmsource == null) map.utmsource = 2;
  if (map.lang == null) map.lang = 3;
  if (map.pipeline_id == null) map.pipeline_id = 4;
  if (map.leads_sum == null) {
    map.leads_sum =
      Array.isArray(fields) && fields.length
        ? fields.length - 1
        : 3;
  }

  return map;
}

// IDs параметров из датасета/селекторов дашборда
const DATE_KEY = 'creation_date_gzep';
const GEO_KEY = 'geo_5gnt';
const UTM_KEY = 'utmsource_bt1a';
const LANG_KEY = 'lang_5rw2';
const PIPE_KEY = 'pipeline_id_kfi1';

const { fromStr, toStr } = parseDateRange(params[DATE_KEY]);
const prevFromStr = shiftMonth(fromStr, -1);
const prevToStr = shiftMonth(toStr, -1);

const periodLabel =
  fromStr === toStr
    ? fmtRuShort(fromStr)
    : `${fmtRuShort(fromStr)}–${fmtRuShort(toStr)}`;
const prevPeriodLabel =
  prevFromStr === prevToStr
    ? fmtRuShort(prevFromStr)
    : `${fmtRuShort(prevFromStr)}–${fmtRuShort(prevToStr)}`;

const geoValues = parseStringFilter(params[GEO_KEY]);
const hasGeoFilter = geoValues.length > 0;
const geoSet = new Set(geoValues);

const utmValues = parseStringFilter(params[UTM_KEY]);
const hasUtmFilter = utmValues.length > 0;
const utmSet = new Set(utmValues);

const langValues = parseStringFilter(params[LANG_KEY]);
const hasLangFilter = langValues.length > 0;
const langSet = new Set(langValues);

const pipeValues = parseStringFilter(params[PIPE_KEY]);
const hasPipeFilter = pipeValues.length > 0;
const pipeSet = new Set(pipeValues);

const idx = buildIndexMap(src);

const rows = extractRows(src);
let currentSum = 0;
let prevSum = 0;

function col(r, i) {
  return r && i != null && i < r.length ? r[i] : null;
}

for (let i = 0; i < rows.length; i++) {
  const r = rows[i];
  const dateStr = String(cellValue(col(r, idx.creation_date)) || '').slice(0, 10);
  if (!dateStr) continue;

  const geo = String(cellValue(col(r, idx.geo)) ?? '∅');
  if (hasGeoFilter && !geoSet.has(geo)) continue;

  const utmsource = String(cellValue(col(r, idx.utmsource)) ?? '∅');
  if (hasUtmFilter && !utmSet.has(utmsource)) continue;

  const lang = String(cellValue(col(r, idx.lang)) ?? '∅');
  if (hasLangFilter && !langSet.has(lang)) continue;

  const pipelineId = String(cellValue(col(r, idx.pipeline_id)) ?? '∅');
  if (hasPipeFilter && !pipeSet.has(pipelineId)) continue;

  const leads = safeNum(col(r, idx.leads_sum)); // leads_sum

  if (dateStr >= fromStr && dateStr <= toStr) currentSum += leads;
  if (dateStr >= prevFromStr && dateStr <= prevToStr) prevSum += leads;
}

let diffPct = null;
if (prevSum === 0) diffPct = currentSum === 0 ? 0 : null;
else diffPct = ((currentSum - prevSum) / prevSum) * 100;

const payload = {
  periodLabel,
  prevPeriodLabel,
  currentSum,
  prevSum,
  diffPct,
};

module.exports = {
  render: Editor.wrapFn({
    fn: function (options, cfg) {
      function formatInt(n) {
        const x = Math.round(Number(n) || 0);
        // NBSP чтобы число не переносилось на новую строку в узких карточках
        return x.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '\u00A0');
      }

      const card = document.createElement('div');
      card.style.setProperty('height', '100%');
      card.style.setProperty('width', '100%');
      card.style.setProperty('box-sizing', 'border-box');
      card.style.setProperty('display', 'flex');
      card.style.setProperty('flex-direction', 'column');
      card.style.setProperty('justify-content', 'center');
      card.style.setProperty('padding', '12px 14px');
      card.style.setProperty(
        'font-family',
        'var(--g-font-family-sans, var(--g-font-family-base, "YS Text","Helvetica Neue","Arial","Helvetica",sans-serif))'
      );
      card.style.setProperty(
        'color',
        'var(--g-color-text-primary, #111827)'
      );

      const title = document.createElement('div');
      title.textContent = 'Лиды';
      title.style.setProperty('font-size', '13px');
      title.style.setProperty('font-weight', '500');
      title.style.setProperty('line-height', '1.2');
      title.style.setProperty('margin-bottom', '4px');

      const row = document.createElement('div');
      row.style.setProperty('display', 'flex');
      row.style.setProperty('align-items', 'baseline');
      row.style.setProperty('gap', '8px');
      row.style.setProperty('flex-wrap', 'nowrap');

      const value = document.createElement('div');
      value.textContent = formatInt(cfg.currentSum);
      value.style.setProperty('font-size', '24px');
      value.style.setProperty('font-weight', '500');
      value.style.setProperty('line-height', '1.2');
      value.style.setProperty('color', '#4DA2F1');
      value.style.setProperty('white-space', 'nowrap');

      const diff = document.createElement('div');
      let diffText = '—';
      let diffColor = 'var(--g-color-text-secondary, #6b7280)';
      if (cfg.diffPct !== null) {
        const s = cfg.diffPct.toFixed(1).replace('.', ',');
        diffText = (cfg.diffPct > 0 ? '+' : '') + s + '%';
        if (cfg.diffPct > 0) diffColor = 'var(--g-color-text-positive, #16a34a)';
        else if (cfg.diffPct < 0)
          diffColor = 'var(--g-color-text-danger, #dc2626)';
      }
      diff.textContent = diffText;
      diff.style.setProperty('font-size', '11.5px');
      diff.style.setProperty('font-weight', '400');
      diff.style.setProperty('color', diffColor);
      diff.style.setProperty('white-space', 'nowrap');

      row.appendChild(value);
      row.appendChild(diff);

      const sub = document.createElement('div');
      sub.style.setProperty('font-size', '11px');
      sub.style.setProperty('margin-top', '4px');
      sub.style.setProperty(
        'color',
        'var(--g-color-text-secondary, #6b7280)'
      );

      const subNum = document.createElement('span');
      subNum.textContent = formatInt(cfg.prevSum);
      subNum.style.setProperty('font-weight', '500');

      const prevLabel = String(cfg.prevPeriodLabel || '').replace('–', ' - ');
      const subText = document.createElement('span');
      subText.textContent = ` (${prevLabel})`;

      sub.appendChild(subNum);
      sub.appendChild(subText);

      card.appendChild(title);
      card.appendChild(row);
      card.appendChild(sub);

      return Editor.generateHtml(card);
    },
    args: [payload],
    libs: [],
  }),
};

